<Project Sdk="Microsoft.NET.Sdk">
  <PropertyGroup>
    <OutputType>Exe</OutputType>
    <TargetFramework>net9.0</TargetFramework>
  </PropertyGroup>
  <ItemGroup>
    <PackageReference Include="MSBuild.StructuredLogger" Version="2.2.386" />
  </ItemGroup>
</Project>
EOF

cat > /tmp/parse_binlog.cs << 'EOF'
using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;
using System.Collections.Generic;

var build = BinaryLog.ReadBuild(args[0]);
var errors = build.FindChildrenRecursive<Error>();
var warnings = build.FindChildrenRecursive<Warning>();

Console.WriteLine($"=== BUILD RESULT: {(build.Succeeded ? "SUCCESS" : "FAILED")} ===");
Console.WriteLine($"Total errors: {errors.Count()}");
Console.WriteLine($"Total warnings: {warnings.Count()}");
Console.WriteLine();

Console.WriteLine("=== ERRORS ===");
foreach (var error in errors)
{
    var project = "";
    var parent = error.Parent;
    while (parent != null)
    {
        if (parent is Project p) { project = p.Name; break; }
        parent = (parent as TreeNode)?.Parent;
    }
    Console.WriteLine($"[{project}] {error.Code}: {error.Text}");
    if (!string.IsNullOrEmpty(error.File))
        Console.WriteLine($"  File: {error.File}({error.LineNumber},{error.ColumnNumber})");
    Console.WriteLine();
}
EOF

