using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;

var build = BinaryLog.ReadBuild(args[0]);

// Show all projects
Console.WriteLine("=== PROJECTS ===");
var projects = build.FindChildrenRecursive<Project>();
foreach (var p in projects)
    Console.WriteLine($"  {p.Name} - Succeeded: {p.Succeeded}");

// Check if any project failed due to dependency
Console.WriteLine("\n=== DEPENDENCY ANALYSIS ===");
var failedProjects = projects.Where(p => !p.Succeeded).Select(p => p.Name).Distinct().ToList();
Console.WriteLine($"Failed projects: {string.Join(", ", failedProjects)}");

// Look for project references  
Console.WriteLine("\n=== PROJECT REFERENCES (from messages) ===");
var messages = build.FindChildrenRecursive<Message>();
foreach (var m in messages.Where(m => m.Text != null && m.Text.Contains("ProjectReference")))
    Console.WriteLine($"  {m.Text}");
EOF

