using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;

var build = BinaryLog.ReadBuild(args[0]);
var projects = build.FindChildrenRecursive<Project>();

Console.WriteLine("=== ALL PROJECTS ===");
foreach (var p in projects.GroupBy(p => p.Name))
    Console.WriteLine($"  {p.Key} - Succeeded: {p.Any(x => x.Succeeded)}");

Console.WriteLine("\n=== FAILED PROJECTS ===");
foreach (var p in projects.Where(p => !p.Succeeded).GroupBy(p => p.Name))
    Console.WriteLine($"  {p.Key}");

Console.WriteLine("\n=== PACKAGE REFERENCES ===");
var items = build.FindChildrenRecursive<Item>();
foreach (var item in items.Where(i => i.Name == "PackageReference").Select(i => i.Text).Distinct())
    Console.WriteLine($"  {item}");

Console.WriteLine("\n=== ERRORS ===");
var errors = build.FindChildrenRecursive<Error>();
foreach (var error in errors)
{
    Console.WriteLine($"  {error.Code}: {error.Text}");
    Console.WriteLine($"    File: {error.File}({error.LineNumber})");
}
EOF

