using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;

var build = BinaryLog.ReadBuild(args[0]);

// Get all items with more detail
var items = build.FindChildrenRecursive<Item>();
Console.WriteLine("=== ALL ITEM TYPES ===");
foreach (var g in items.GroupBy(i => i.Name).OrderBy(g => g.Key))
    Console.WriteLine($"  {g.Key}: {g.Count()}");

Console.WriteLine("\n=== PackageReference items ===");
foreach (var item in items.Where(i => i.Name == "PackageReference"))
{
    var project = "";
    var parent = item.Parent;
    while (parent != null)
    {
        if (parent is Project p) { project = p.Name; break; }
        parent = (parent as TreeNode)?.Parent;
    }
    Console.WriteLine($"  [{project}] {item.Text} -> {item.NameAndEquals}{item.ShortenedText}");
}

// Look at AddItem for PackageReference
Console.WriteLine("\n=== AddItem entries ===");
var addItems = build.FindChildrenRecursive<AddItem>();
foreach (var ai in addItems.Where(a => a.Name == "PackageReference" || a.Title?.Contains("PackageReference") == true))
{
    Console.WriteLine($"  {ai.Title} / {ai.Name}");
    foreach (var child in ai.Children.OfType<Item>())
        Console.WriteLine($"    -> {child.Text}");
}

// Check for NuGet restore issues
Console.WriteLine("\n=== NuGet/Restore Messages ===");
var messages = build.FindChildrenRecursive<Message>();
foreach (var m in messages.Where(m => m.Text?.Contains("Newtonsoft") == true || m.Text?.Contains("restore") == true || m.Text?.Contains("NU") == true).Take(20))
    Console.WriteLine($"  {m.Text}");
EOF

