using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;

var build = BinaryLog.ReadBuild(args[0]);

// Let's look at the raw text in the binlog for Services.csproj content
var allText = build.FindChildrenRecursive<TextNode>();

// Get properties for Services project
Console.WriteLine("=== Properties with 'PackageReference' or 'Newtonsoft' ===");
var props = build.FindChildrenRecursive<Property>();
foreach (var p in props.Where(x => x.Name?.Contains("Newtonsoft") == true || x.Value?.Contains("Newtonsoft") == true))
    Console.WriteLine($"  {p.Name} = {p.Value}");

// Look at the actual csproj content via NameValueNode or similar
Console.WriteLine("\n=== Searching for project file content ===");
var namedNodes = build.FindChildrenRecursive<NamedNode>();
foreach (var n in namedNodes.Where(x => x.Name?.Contains("Services.csproj") == true).Take(5))
    Console.WriteLine($"  Type: {n.GetType().Name}, Name: {n.Name}");

// Get source file listing
Console.WriteLine("\n=== Compile items for Services ===");
var items = build.FindChildrenRecursive<Item>();
foreach (var item in items.Where(i => i.Name == "Compile"))
{
    var project = "";
    var parent = item.Parent;
    while (parent != null)
    {
        if (parent is Project p) { project = p.Name; break; }
        parent = (parent as TreeNode)?.Parent;
    }
    if (project.Contains("Services"))
        Console.WriteLine($"  {item.Text}");
}

// Get the source content from the error context
Console.WriteLine("\n=== Source file line from errors ===");
var errors = build.FindChildrenRecursive<Error>();
foreach (var error in errors)
    Console.WriteLine($"  {error.File}:{error.LineNumber} - {error.Code}: {error.Text}");

// Try to find NuGet package resolution
Console.WriteLine("\n=== Resolved references for Services ===");
foreach (var item in items.Where(i => i.Name == "Reference" || i.Name == "ResolvedCompileFileDefinitions"))
{
    var project = "";
    var parent = item.Parent;
    while (parent != null)
    {
        if (parent is Project p) { project = p.Name; break; }
        parent = (parent as TreeNode)?.Parent;
    }
    if (project.Contains("Services") && item.Text?.Contains("Newtonsoft") == true)
        Console.WriteLine($"  [{item.Name}] {item.Text}");
}
EOF

